// ── STEP 3: Clean & Validate Lead Data ──────────────────
const body = $input.first().json.body || $input.first().json;

// Normalise URL
let rawUrl = (body.url || body.website || '').trim();
if (rawUrl && !rawUrl.startsWith('http')) rawUrl = 'https://' + rawUrl;

let hostname = '';
try { hostname = new URL(rawUrl).hostname.replace('www.', ''); } catch(e) {}

// Clean fields
const lead = {
  name:      (body.name || '').trim(),
  company:   (body.company || '').trim(),
  email:     (body.email || '').trim().toLowerCase(),
  phone:     (body.phone || '').trim(),
  url:       rawUrl,
  hostname:  hostname,
  challenge: (body.challenge || 'Not specified').trim(),
  submitted: new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
  timestamp: new Date().toISOString()
};

// Basic validation
if (!lead.email || !lead.email.includes('@')) {
  throw new Error('Invalid email: ' + lead.email);
}
if (!lead.url) {
  throw new Error('No website URL provided');
}

return [{ json: lead }];

// ── STEP 4: Basic Website Pre-Audit ─────────────────────
// Uses HTTP request to fetch the website HTML and check for key signals
// This runs BEFORE the Claude AI step so we pass real data to Claude

const lead = $input.first().json;
const url = lead.url;

// We'll do the actual HTTP fetch in the next HTTP node.
// This node just prepares the audit checklist structure.

const audit = {
  url: url,
  hostname: lead.hostname,
  checks: {
    ga4: false,
    gtm: false,
    metaPixel: false,
    serverSide: false,
    hasTitle: false,
    hasDescription: false,
    hasH1: false,
    hasSchema: false,
    hasOG: false,
    hasCanonical: false,
    hasSitemap: false,
    isHttps: url.startsWith('https://'),
    hasForms: false,
    hasSSL: url.startsWith('https://')
  },
  titleText: '',
  descText: '',
  titleLength: 0,
  descLength: 0,
  issuesFound: [],
  passesFound: [],
  score: 0
};

return [{ json: { lead, audit } }];

// ── STEP 6: Analyse HTML for Tracking & SEO Signals ─────
const { lead, audit } = $('4. Prepare Audit Structure').first().json;
const response = $input.first().json;

let html = '';
try {
  const parsed = typeof response === 'string' ? JSON.parse(response) : response;
  html = parsed.contents || parsed || '';
} catch(e) {
  html = String(response || '');
}

const h = String(html);
const lh = h.toLowerCase();

if (!h || h.length < 100) {
  audit.fetchFailed = true;
  audit.fetchNote = 'Could not fetch website HTML — site may block crawlers or be down.';
  return [{ json: { lead, audit } }];
}

audit.fetchFailed = false;

// ── TRACKING CHECKS ──
audit.checks.ga4        = lh.includes('gtag') && (lh.includes('g-') || lh.includes('googletagmanager'));
audit.checks.gtm        = lh.includes('googletagmanager.com/gtm.js') || lh.includes('gtm.js');
audit.checks.metaPixel  = lh.includes('connect.facebook.net') || lh.includes('fbevents.js') || (lh.includes('fbq(') && lh.includes('pageview'));
audit.checks.serverSide = lh.includes('stape') || lh.includes('sgtm') || (lh.includes('gtm') && lh.includes('server'));

// ── ON-PAGE SEO ──
const titleMatch = h.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
audit.titleText   = titleMatch ? titleMatch[1].replace(/<[^>]+>/g,'').trim() : '';
audit.titleLength = audit.titleText.length;
audit.checks.hasTitle = audit.titleLength >= 20;

const descMatch = h.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)/i)
               || h.match(/<meta[^>]*content=["']([^"']*)[^>]*name=["']description["']/i);
audit.descText   = descMatch ? descMatch[1].trim() : '';
audit.descLength = audit.descText.length;
audit.checks.hasDescription = audit.descLength >= 50;

audit.checks.hasH1        = (h.match(/<h1[\s>]/gi) || []).length === 1;
audit.checks.hasSchema    = lh.includes('application/ld+json') || lh.includes('itemtype=');
audit.checks.hasOG        = lh.includes('og:title') || lh.includes('og:description');
audit.checks.hasCanonical = lh.includes('rel="canonical"') || lh.includes("rel='canonical'");
audit.checks.hasForms     = lh.includes('<form');
audit.checks.hasViewport  = lh.includes('viewport');

// ── SCORE ──
const weights = {
  isHttps: 8, ga4: 10, gtm: 8, metaPixel: 8,
  hasTitle: 8, hasDescription: 8, hasH1: 7,
  hasSchema: 6, hasOG: 5, hasCanonical: 5,
  hasViewport: 5, hasForms: 5
};
let total = 0, max = 0;
Object.entries(weights).forEach(([k, w]) => {
  max += w;
  if (audit.checks[k]) total += w;
});
audit.score = Math.round((total / max) * 100);

// ── ISSUES & PASSES ──
audit.issuesFound = [];
audit.passesFound = [];

if (!audit.checks.ga4)         audit.issuesFound.push('GA4 not detected — no analytics data being collected');
if (!audit.checks.gtm)         audit.issuesFound.push('Google Tag Manager missing — conversion tracking is limited');
if (!audit.checks.metaPixel)   audit.issuesFound.push('Meta Pixel not found — Meta/Instagram ads cannot track conversions');
if (!audit.checks.serverSide)  audit.issuesFound.push('No server-side tracking detected — likely losing 30-50% of conversion data to ad blockers and iOS');
if (!audit.checks.hasTitle)    audit.issuesFound.push('Page title missing or too short — major SEO impact');
if (!audit.checks.hasDescription) audit.issuesFound.push('Meta description missing — affects CTR from Google search results');
if (!audit.checks.hasH1)       audit.issuesFound.push('H1 heading issue — multiple or missing H1 hurts keyword rankings');
if (!audit.checks.hasSchema)   audit.issuesFound.push('No schema markup — missing rich result eligibility in Google');
if (!audit.checks.hasOG)       audit.issuesFound.push('No Open Graph tags — social sharing previews will look broken');
if (!audit.checks.hasCanonical) audit.issuesFound.push('No canonical tag — risk of duplicate content penalties');
if (!audit.checks.isHttps)     audit.issuesFound.push('Site not on HTTPS — critical security and ranking issue');

if (audit.checks.ga4)          audit.passesFound.push('GA4 is active');
if (audit.checks.gtm)          audit.passesFound.push('Google Tag Manager found');
if (audit.checks.metaPixel)    audit.passesFound.push('Meta Pixel is firing');
if (audit.checks.isHttps)      audit.passesFound.push('HTTPS enabled');
if (audit.checks.hasSchema)    audit.passesFound.push('Schema markup present');
if (audit.checks.hasOG)        audit.passesFound.push('Open Graph tags set');

return [{ json: { lead, audit } }];

// ── STEP 7: Write to Google Sheets ──────────────────────
// Prepares the row data. The actual Sheets node follows.
const { lead, audit } = $input.first().json;

const row = {
  Timestamp:     lead.submitted,
  Name:          lead.name,
  Company:       lead.company,
  Email:         lead.email,
  Phone:         lead.phone || '—',
  Website:       lead.url,
  Challenge:     lead.challenge,
  Score:         audit.score,
  GA4:           audit.checks.ga4 ? 'YES' : 'NO',
  GTM:           audit.checks.gtm ? 'YES' : 'NO',
  MetaPixel:     audit.checks.metaPixel ? 'YES' : 'NO',
  ServerSide:    audit.checks.serverSide ? 'YES' : 'NO',
  Issues:        audit.issuesFound.join(' | '),
  Passes:        audit.passesFound.join(' | '),
  Status:        'New Lead',
  AuditSentAt:   '',
  Notes:         ''
};

return [{ json: { lead, audit, row } }];

// ── STEP 9: Build Claude AI Prompt ──────────────────────
const { lead, audit } = $('6. Analyse Tracking & SEO').first().json;

const issuesList = audit.issuesFound.length > 0
  ? audit.issuesFound.map((i, n) => `${n+1}. ${i}`).join('\n')
  : 'No major issues detected in automated scan.';

const passesList = audit.passesFound.length > 0
  ? audit.passesFound.join(', ')
  : 'None detected in automated scan.';

const prompt = `You are a senior digital marketing analyst at Vyom Intelligence, a specialist agency for Marketing Analytics, Conversion Tracking, and Automation.

A business just submitted a free website audit request. Here is their data:

Name: ${lead.name}
Company: ${lead.company}
Website: ${lead.url}
Biggest challenge: ${lead.challenge}
Audit score: ${audit.score}/100

ISSUES DETECTED (automated scan):
${issuesList}

PASSES (what's working):
${passesList}

Title tag: ${audit.titleText || 'Not found'} (${audit.titleLength} chars)
Meta description: ${audit.descText ? audit.descText.slice(0,80)+'...' : 'Not found'} (${audit.descLength} chars)

Write a personalised audit acknowledgement email from Vyom Intelligence to ${lead.name}.

The email must:
1. Open with a warm, professional greeting using their first name
2. Confirm we received their audit request for ${lead.hostname}
3. Mention 2-3 specific issues from the scan above (make them sound alarming but not scary — use plain language, no jargon)
4. Mention what's working (if anything) so it feels balanced
5. Tell them they will receive the full detailed audit report within 24 hours
6. End with a soft CTA: "If you'd like to discuss this sooner, reply to this email or WhatsApp us at [PHONE]"
7. Sign off as: Sagar | Vyom Intelligence | vyomintelligence.com

Tone: Professional, warm, confident. Like a consultant who already knows their business.
Length: 150-200 words maximum.
Do NOT use buzzwords like 'leverage', 'synergy', 'holistic'.
Do NOT use bullet points in the email — write in short paragraphs.
Output ONLY the email body. No subject line. No notes.`;

return [{ json: { lead, audit, prompt } }];

// ── STEP 11: Extract AI Email Body ──────────────────────
const { lead, audit } = $('9. Build Claude AI Prompt').first().json;
const claudeResponse = $input.first().json;

let emailBody = '';
try {
  emailBody = claudeResponse.content[0].text || '';
} catch(e) {
  // Fallback if Claude API fails
  emailBody = `Hi ${lead.name},

Thank you for submitting your free website audit request for ${lead.hostname}.

Our team has received your request and will send you a full personalised audit report within 24 hours. We have already run an initial automated scan and identified ${audit.issuesFound.length} areas to review.

If you would like to discuss your website sooner, simply reply to this email.

Best regards,
Sagar | Vyom Intelligence
vyomintelligence.com`;
}

// Build subject line
const scoreLabel = audit.score >= 75 ? 'Good baseline' : audit.score >= 50 ? 'Several gaps found' : 'Critical issues found';
const subject = `Your free audit for ${lead.hostname} — ${scoreLabel} (${audit.score}/100)`;

// Build WhatsApp alert message
const waMessage = `🔔 *New Audit Lead — Vyom Intelligence*

*Name:* ${lead.name}
*Company:* ${lead.company}
*Email:* ${lead.email}
*Phone:* ${lead.phone || 'Not provided'}
*Website:* ${lead.url}
*Challenge:* ${lead.challenge}

📊 *Pre-Audit Score:* ${audit.score}/100
✅ *Passes:* ${audit.passesFound.join(', ') || 'None'}
❌ *Issues:* ${audit.issuesFound.slice(0,3).join(' | ')}

👉 Action: Send full audit within 24hrs`;

return [{ json: { lead, audit, emailBody, subject, waMessage } }];

// ── STEP 15: 24-Hour Follow-Up Scheduler ────────────────
// This prepares data for the follow-up. The Wait node handles the delay.
const { lead, audit } = $('11. Extract AI Email').first().json;

return [{ json: {
  lead,
  audit,
  followUpSubject: `Your full audit report — ${lead.hostname}`,
  reminderNote: `REMINDER: Send full manual audit to ${lead.email} for ${lead.url}. Score was ${audit.score}/100. Issues: ${audit.issuesFound.slice(0,2).join(', ')}.`
} }];
